/**
 * A handler that implements reversible appending of shapes
 * to a source shape.
 *
 */
export default class AppendShapeHandler {
  static $inject: string[];

  /**
   * @param modeling
   */
  constructor(modeling: Modeling);

  /**
   * Creates a new shape.
   *
   * @param context
   */
  preExecute(context: {
      shape: Partial<Shape>;
      source: Element;
      parent: Parent;
      position: Point;
  }): void;

  postExecute(context: any): void;
}

type Element = import("../../../model/Types.js").Element;
type Parent = import("../../../model/Types.js").Parent;
type Shape = import("../../../model/Types.js").Shape;
type Point = import("../../../util/Types.js").Point;
type Modeling = import("../Modeling.js").default;